node -e "
const fs = require('fs');
const dash = JSON.parse(fs.readFileSync('D:/ClaudeWorkspace/08_客户跟进/Okki/output/.dashboard_snapshot.json', 'utf8'));
const heat = JSON.parse(fs.readFileSync('D:/ClaudeWorkspace/08_客户跟进/Okki/data/heat_classification.json', 'utf8'));

const dashNames = new Set(dash.customers.map(c => c.name.trim().toLowerCase()));
const heatNames = new Set(heat.results.map(c => c.name.trim().toLowerCase()));

const overlap = [...dashNames].filter(n => heatNames.has(n));
const onlyDash = [...dashNames].filter(n => !heatNames.has(n));
const onlyHeat = [...heatNames].filter(n => !dashNames.has(n));

console.log('Names in dashboard:', dashNames.size);
console.log('Names in heat_classification:', heatNames.size);
console.log('Overlapping names:', overlap.length);
console.log('Only in dashboard (sample 10):', onlyDash.slice(0,10));
console.log('Only in heat_classification (sample 10):', onlyHeat.slice(0,10));
"

